firmware_template.source:
#include "crypto_aes.h"
#include <mbedtls/aes.h>
static mbedtls_aes_context _ctx;
static uint8_t _iv[16]={0};
void crypto_setup(const uint8_t*key){mbedtls_aes_init(&_ctx);mbedtls_aes_setkey_enc(&_ctx,key,256);Serial.println("[aes] OK");}
bool crypto_encrypt(const uint8_t*in,uint8_t*out,size_t len){uint8_t iv[16];memcpy(iv,_iv,16);return mbedtls_aes_crypt_cbc(&_ctx,MBEDTLS_AES_ENCRYPT,len,iv,in,out)==0;}
bool crypto_decrypt(const uint8_t*in,uint8_t*out,size_t len){uint8_t iv[16];memcpy(iv,_iv,16);mbedtls_aes_setkey_dec(&_ctx,(const uint8_t*)&_ctx,256);return mbedtls_aes_crypt_cbc(&_ctx,MBEDTLS_AES_DECRYPT,len,iv,in,out)==0;}
